PORT = int(os.environ.get("PORT", 8080))

# ===== DATABASE (SQLite local / PostgreSQL en Render) =====
DATABASE_URL = os.environ.get("DATABASE_URL","")
USE_PG = bool(DATABASE_URL)

if USE_PG:
    try:
        import psycopg2, psycopg2.extras
    except ImportError:
        print("WARNING: psycopg2 no instalado — usando SQLite")
        USE_PG = False
if not USE_PG:
    import sqlite3

DB_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "sem_data.db")

def db():
    if USE_PG:
        conn = psycopg2.connect(DATABASE_URL)
        return conn
    else:
        conn = sqlite3.connect(DB_FILE)
        conn.row_factory = sqlite3.Row
        return conn

def qmark(sql):
    """Convert ? placeholders to %s for PostgreSQL"""
    if USE_PG:
        return sql.replace("?", "%s")
    return sql

def fetchall(cursor):
    if USE_PG:
        cols = [d[0] for d in cursor.description]
        return [dict(zip(cols,r)) for r in cursor.fetchall()]
    return [dict(r) for r in cursor.fetchall()]

def fetchone(cursor):
    if USE_PG:
        if cursor.description:
            cols = [d[0] for d in cursor.description]
            row = cursor.fetchone()
            return dict(zip(cols,row)) if row else None
    else:
        row = cursor.fetchone()
        return dict(row) if row else None

def autoincrement():
    return "SERIAL PRIMARY KEY" if USE_PG else "INTEGER PRIMARY KEY AUTOINCREMENT"

def lastid(cursor):
    if USE_PG:
        cursor.execute("SELECT lastval()")
        return cursor.fetchone()[0]
    return cursor.lastrowid

def init_db():
    conn = db()
    c = conn.cursor()
    ai = autoincrement()
    c.execute(f"""CREATE TABLE IF NOT EXISTS clientes (
        id {ai},
        nombre TEXT NOT NULL,
        institucion TEXT,
        telefono TEXT,
        cuit TEXT,
        situacion_arca TEXT,
        email TEXT,
        direccion TEXT,
        notas TEXT,
        fecha_creacion TEXT,
        creado_por TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS equipos_taller (
        id {ai},
        cliente TEXT,
        telefono TEXT,
        equipo TEXT,
        marca TEXT,
        modelo TEXT,
        serie TEXT,
        problema TEXT,
        estado TEXT DEFAULT 'Ingresado',
        tecnico_asignado TEXT,
        observaciones TEXT,
        fecha_ingreso TEXT,
        fecha_estado TEXT,
        es_propio INTEGER DEFAULT 0,
        creado_por TEXT,
        cliente_id INTEGER
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS recordatorios (
        id {ai},
        cliente_id INTEGER,
        equipo TEXT,
        fecha_ultimo TEXT,
        fecha_proximo TEXT,
        notas TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS permisos (
        id {ai},
        usuario_nombre TEXT UNIQUE NOT NULL,
        secciones TEXT DEFAULT '{{}}'
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS config (
        id {ai},
        clave TEXT UNIQUE NOT NULL,
        valor TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS patrones (
        id {ai},
        tipo TEXT NOT NULL,
        marca_modelo TEXT,
        numero_serie TEXT,
        certificado TEXT,
        fecha_calibracion TEXT,
        fecha_vencimiento TEXT,
        notas TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS historial_equipos (
        id {ai},
        equipo_id INTEGER,
        cliente TEXT,
        equipo TEXT,
        marca TEXT,
        modelo TEXT,
        serie TEXT,
        fecha TEXT,
        trabajo TEXT,
        tecnico TEXT,
        tipo_trabajo TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS stock (
        id {ai},
        nombre TEXT NOT NULL,
        descripcion TEXT,
        cantidad INTEGER DEFAULT 0,
        cantidad_minima INTEGER DEFAULT 1,
        unidad TEXT,
        notas TEXT
    )""")
    c.execute(f"""CREATE TABLE IF NOT EXISTS finanzas (
        id {ai},
        tipo TEXT,
        concepto TEXT,
        monto REAL,
        fecha TEXT,
        equipo_taller_id INTEGER,
        cliente TEXT,
        factura_num TEXT,
        notas TEXT,
        creado_por TEXT
    )""")
    conn.commit(); conn.close()

init_db()

def next_reg(key):
    """Obtiene y autoincrementa el número de registro en la tabla config."""
    conn = db(); c = conn.cursor()
    c.execute(qmark("SELECT valor FROM config WHERE clave=?"), (key,))
    row = fetchone(c)
    if row:
        val = int(row["valor"])
        c.execute(qmark("UPDATE config SET valor=? WHERE clave=?"), (str(val+1), key))
    else:
        val = 1
        c.execute(qmark("INSERT INTO config (clave,valor) VALUES (?,?)"), (key, "2"))
    conn.commit(); conn.close()
    return str(val)



LOGO_B64 = ''
CARDIO_B64 = ''
LOGO_REPORT_B64 = ''

def get_ip():
    s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    try:
        s.connect(("8.8.8.8", 80))
        return s.getsockname()[0]
    except:
        return "127.0.0.1"
    finally:
        s.close()

def fmt_fecha(iso):
    if not iso: return ""
    meses = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto",
             "septiembre","octubre","noviembre","diciembre"]
    try:
        y, mo, d = iso.split("-")
        return "San Juan, " + str(int(d)) + " de " + meses[int(mo)-1] + " del " + y
    except:
        return iso

def next_year(iso):
    if not iso: return ""
    try:
        d = datetime.strptime(iso, "%Y-%m-%d")
        return d.replace(year=d.year+1).strftime("%d/%m/%Y")
    except:
        return ""

_TMP = []

def add_logo_to_ws(ws, w=80, h=40, use_report_logo=True):
    try:
        from openpyxl.drawing.image import Image as XLImg
        raw = base64.b64decode(LOGO_REPORT_B64 if use_report_logo else LOGO_B64)
        suf = ".jpg" if raw[:2] == b"\xff\xd8" else ".png"
        tmp = tempfile.NamedTemporaryFile(suffix=suf, delete=False)
        tmp.write(raw); tmp.flush(); tmp.close()
        _TMP.append(tmp.name)
        img = XLImg(tmp.name)
        img.width = w; img.height = h; img.anchor = "A1"
        ws.add_image(img)
    except:
        pass

def cleanup_tmp():
    while _TMP:
        try: os.unlink(_TMP.pop())
        except: pass

