def fill_cardio(d):
    import openpyxl
    raw = base64.b64decode(CARDIO_B64)
    wb = openpyxl.load_workbook(io.BytesIO(raw))
    ws = wb["Hoja1"]
    def sc(a,v):
        if v is not None and str(v).strip() not in ("","nan"): ws[a]=v
    def scn(a,v):
        try:
            f=float(v)
            if f==f: ws[a]=f
        except: pass
    sc("F6",  fmt_fecha(d.get("fe","")))
    sc("D9",  d.get("inst",""))
    sc("D10", d.get("fe",""))
    if d.get("cuit",""): sc("B11", "CUIT: "+d.get("cuit",""))
    if d.get("tel_cli",""): sc("F11", "Tel: "+d.get("tel_cli",""))
    sc("D13", d.get("ma",""))
    sc("D14", d.get("mo",""))
    sc("D15", d.get("se",""))
    scn("D53", d.get("n1_esp","100"))
    scn("D54", d.get("n2_esp","200"))
    scn("D55", d.get("emax_esp","360"))
    scn("D56", d.get("pe_esp","200"))
    scn("F52", d.get("e_min",""))
    scn("F53", d.get("n1",""))
    scn("F54", d.get("n2",""))
    scn("F55", d.get("emax_res",""))
    scn("F56", d.get("pe",""))
    scn("F57", d.get("tc",""))
    for i,v in enumerate(d.get("rep",[])):
        scn("F"+str(63+i), v)
    for i,v in enumerate(d.get("bat",[])):
        scn("E"+str(78+i), v)
    sc("E99",  d.get("fo","OK"))
    scn("E100", d.get("r60",""))
    scn("E101", d.get("r120",""))
    scn("E102", d.get("ab",""))
    scn("E103", d.get("aa",""))
    scn("E108", d.get("si",""))
    scn("E109", d.get("re2",""))
    sc("B114", d.get("obs",""))
    sc("B130", d.get("tecnico",""))
    buf = io.BytesIO(); wb.save(buf); buf.seek(0)
    return buf.read()


