def _tec_name(tec):
    return {"Jonathan":"Tec.Jonatan Derman","Pablo Morales":"Tec.Pablo Morales",
            "Agustín Morales":"Tec.Agustín Morales","Gael":"Tec.Gael"}.get(tec, f"Tec.{tec}")

def _hdr_img(ws, tec, img_w, img_h, anchor="A1"):
    """Inserta imagen de encabezado según técnico."""
    try:
        from openpyxl.drawing.image import Image as XLImg
        path = _LOGO_JON_PATH if tec == "Jonathan" else _LOGO_SEM_PATH
        img = XLImg(path)
        img.width = img_w; img.height = img_h; img.anchor = anchor
        ws.add_image(img)
    except Exception as e:
        print(f"WARNING _hdr_img: {e}")

CEL  = "FF74BACD"   # celeste SEM
WHT  = "FFFFFFFF"
BLK  = "FF000000"
GRY  = "FFF0F0F0"
GN   = "FF16A34A"
RD   = "FFDC2626"
OR   = "FFD97706"

def _mkfont(bold=False, sz=10, col="FF000000"):
    from openpyxl.styles import Font
    return Font(name="Calibri", bold=bold, size=sz, color=col)

def _mkfill(col):
    from openpyxl.styles import PatternFill
    return PatternFill("solid", fgColor=col)

def _mkaln(h="left", v="center", wrap=False):
    from openpyxl.styles import Alignment
    return Alignment(horizontal=h, vertical=v, wrap_text=wrap)

def _sc(ws, ref, val, bg=None, ft=None, al=None):
    c = ws[ref]
    c.value = val
    if bg: c.fill = _mkfill(bg)
    if ft: c.font = ft
    if al: c.alignment = al

def _next_year(fe):
    if not fe: return ""
    try:
        parts = fe.split("-")
        return str(int(parts[0])+1) + "-" + parts[1] + "-" + parts[2]
    except:
        return ""


# ─────────────────────────────────────────────────────────────────────
# ECG  —  respeta columnas del template _SIN_ROTULO (B-G)
# ─────────────────────────────────────────────────────────────────────
def gen_ecg(d):
    import openpyxl
    wb = openpyxl.Workbook()
    ws = wb.active; ws.title = "INFORME"
    ws.sheet_view.showGridLines = False
    ws.page_setup.orientation = "portrait"; ws.page_setup.paperSize = 9

    # Columnas exactas del template ECG _OK  (A-G usadas)
    for col, w in zip("ABCDEFG", [10.71, 18.42, 11.28, 10.71, 8.0, 10.57, 14.85]):
        ws.column_dimensions[col].width = w

    tec = d.get("tecnico", "")
    reg = str(d.get("reg", ""))
    fe  = d.get("fecha", "")

    # Fila 1: imagen encabezado — ancho ajustado a cols A-G (~487px)
    ws.row_dimensions[1].height = 105
    _hdr_img(ws, tec, img_w=546, img_h=130, anchor="B1")

    # Fila 2: título
    ws.row_dimensions[2].height = 18.75
    ws.merge_cells("B2:G2")
    _sc(ws,"B2","Informe de Verificación de Electrocardiografo",
        CEL, _mkfont(True,14), _mkaln("center"))

    # Filas 3-6: info equipo
    for r in range(3,7): ws.row_dimensions[r].height = 15
    for r,(lbl,k) in enumerate([("Equipo","ma"),("Modelo","mo"),
                                  ("Numero de Serie","se"),("Institucion","inst")],3):
        ws.row_dimensions[r].height = 15
        _sc(ws,f"B{r}",lbl, CEL, _mkfont(sz=10), _mkaln("left"))
        ws.merge_cells(f"B{r}:C{r}")
        val = d.get(k,"").upper() if k=="ma" else d.get(k,"")
        _sc(ws,f"D{r}", val, WHT, _mkfont(sz=10))
        ws.merge_cells(f"D{r}:F{r}")
    _sc(ws,"G3","REGISTRO NRO:", None, _mkfont(True,9), _mkaln("right"))
    ws.cell(row=4,column=7).value = reg
    ws.cell(row=4,column=7).font  = _mkfont(True,11)
    ws.cell(row=4,column=7).alignment = _mkaln("center","center")
    ws.merge_cells("G3:G6")

    # Fila 7: Fecha
    ws.row_dimensions[7].height = 15
    _sc(ws,"B7","Fecha:", CEL, _mkfont(sz=9), _mkaln("left"))
    ws.merge_cells("C7:F7")
    _sc(ws,"C7", fe, WHT, _mkfont(sz=10))

    # Fila 8: header columnas checklist
    ws.row_dimensions[8].height = 20
    ws.merge_cells("B8:D8")
    _sc(ws,"B8","Especificación de trabajo", None, _mkfont(True,9), _mkaln("left"))
    ws.merge_cells("E8:G8")
    _sc(ws,"E8","Conforme / No Conforme / No Aplica", None, _mkfont(sz=8), _mkaln("center"))

    row = 9

    def sec(r, title):
        ws.row_dimensions[r].height = 16
        ws.merge_cells(f"B{r}:G{r}")
        _sc(ws,f"B{r}", title, CEL, _mkfont(True,10), _mkaln("center"))

    def item(r, label, key):
        ws.row_dimensions[r].height = 14
        bg = "FFF8FAFC" if r%2==0 else WHT
        ws.merge_cells(f"B{r}:D{r}")
        _sc(ws,f"B{r}", label, bg, _mkfont(sz=9), _mkaln("left"))
        val = d.get(key,"No Aplica")
        col = GN if val=="Conforme" else (RD if val=="No Conforme" else OR)
        ws.merge_cells(f"E{r}:G{r}")
        _sc(ws,f"E{r}", val, bg, _mkfont(True,9,col), _mkaln("center"))

    sec(row,"Estado general"); row+=1
    for lbl,k in [("Inspeccion visual","iv"),("Estado de cables","cb"),
                  ("Estado de perillas","per"),("Estado de pinzas","pi"),
                  ("Estado de bateria","ba")]:
        item(row,lbl,k); row+=1

    sec(row,"Seguimiento de Frecuencia Cardiaca"); row+=1
    for lbl,k in [("60 bpm","fc60"),("80 bpm","fc80"),("120 bpm","fc120")]:
        item(row,lbl,k); row+=1

    sec(row,"Tipo de Onda"); row+=1
    for lbl,k in [("Normal","on"),("Supraventricular","os"),
                  ("Fibrilacion ventricular","of"),("Flutter auricular","ofl"),
                  ("Triangular","ot"),("Senoidal","osen"),("Cuadrada","oc")]:
        item(row,lbl,k); row+=1

    sec(row,"Amplitud"); row+=1
    for lbl,k in [("0.5 mV","a05"),("1 mV","a1"),("2 mV","a2")]:
        item(row,lbl,k); row+=1

    row+=1
    ws.row_dimensions[row].height = 14
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}","Patron", CEL, _mkfont(True,10), _mkaln("center")); row+=1
    pt = d.get("patron","")
    for line in (pt.split("\n") if pt else [""]):
        ws.row_dimensions[row].height = 14
        ws.merge_cells(f"B{row}:G{row}")
        _sc(ws,f"B{row}",line.strip(), WHT, _mkfont(sz=9)); row+=1

    row+=1
    ws.row_dimensions[row].height = 14
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}","Observaciones", CEL, _mkfont(True,10), _mkaln("center")); row+=1
    for r2 in range(row,row+3): ws.row_dimensions[r2].height = 14
    ws.merge_cells(f"B{row}:G{row+2}")
    _sc(ws,f"B{row}",d.get("obs",""), WHT, _mkfont(sz=9), _mkaln("left","top",True)); row+=3

    row+=1
    ws.row_dimensions[row].height = 14
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}","Mantenimiento", CEL, _mkfont(True,10), _mkaln("center")); row+=1
    ws.row_dimensions[row].height = 14
    ws.merge_cells(f"B{row}:C{row}")
    _sc(ws,f"B{row}","Actual", "FFF0F0F0", _mkfont(True,9))
    ws.merge_cells(f"D{row}:G{row}")
    _sc(ws,f"D{row}", fe, WHT, _mkfont(sz=9)); row+=1
    ws.row_dimensions[row].height = 14
    ws.merge_cells(f"B{row}:C{row}")
    _sc(ws,f"B{row}","Próximo", "FFF0F0F0", _mkfont(True,9))
    ws.merge_cells(f"D{row}:G{row}")
    _sc(ws,f"D{row}", _next_year(fe), WHT, _mkfont(sz=9)); row+=2

    # Firma
    for r2 in range(row,row+3): ws.row_dimensions[r2].height = 15.75
    ws.merge_cells(f"B{row}:G{row+2}")
    _sc(ws,f"B{row}","ENCARGADO DEL MANTENIMIENTO",
        CEL, _mkfont(True,11), _mkaln("center","center")); row+=3
    ws.row_dimensions[row].height = 18
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}", _tec_name(tec), WHT, _mkfont(True,11), _mkaln("center","center"))
    row += 1
    ws.row_dimensions[row].height = 20
    row += 1
    ws.row_dimensions[row].height = 15
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}", "Soluciones Electromédicas SJ", CEL, _mkfont(True,9), _mkaln("center","center"))
    row += 1
    ws.row_dimensions[row].height = 18
    ws.merge_cells(f"B{row}:G{row}")
    _sc(ws,f"B{row}", "_____________________________", WHT, _mkfont(False,10), _mkaln("center","center"))

    buf = io.BytesIO(); wb.save(buf); cleanup_tmp(); buf.seek(0)
    return buf.read()


