def gen_monitor(d):
    import openpyxl
    wb = openpyxl.Workbook()
    ws = wb.active; ws.title = "INFORME"
    ws.sheet_view.showGridLines = False
    ws.page_setup.orientation = "portrait"; ws.page_setup.paperSize = 9

    # Columnas exactas del template Monitor (A-H)
    for col, w in zip("ABCDEFGH", [4.42, 11.85, 7.42, 7.0, 8.0, 15.85, 20.42, 16.0]):
        ws.column_dimensions[col].width = w

    tec = d.get("tecnico","")
    reg = str(d.get("reg",""))
    fe  = d.get("fecha","")

    # Fila 1: imagen — ancho ajustado a cols A-H (~550px)
    ws.row_dimensions[1].height = 105
    _hdr_img(ws, tec, img_w=640, img_h=130, anchor="B1")

    # Fila 2: título
    ws.row_dimensions[2].height = 18.75
    ws.merge_cells("B2:H2")
    _sc(ws,"B2","Informe de Verificación de Monitores Multiparamétricos",
        CEL, _mkfont(True,14), _mkaln("center"))

    # Filas 3-6: info equipo
    for r in range(3,7): ws.row_dimensions[r].height = 15
    for r,(lbl,k) in enumerate([("Equipo","ma"),("Modelo","mo"),
                                  ("Numero de Serie","se"),("Institucion","inst")],3):
        ws.row_dimensions[r].height = 15
        _sc(ws,f"B{r}",lbl, CEL, _mkfont(sz=10), _mkaln("left"))
        ws.merge_cells(f"B{r}:E{r}")
        val = d.get(k,"").upper() if k=="ma" else d.get(k,"")
        _sc(ws,f"F{r}", val, WHT, _mkfont(sz=10))
        ws.merge_cells(f"F{r}:G{r}")
    _sc(ws,"H3","REGISTRO NRO:", None, _mkfont(True,9), _mkaln("right"))
    ws.cell(row=4,column=8).value = reg
